class WadFile {
  private handle: number;
  private numLumps: number;
  private infotable: LumpInfo[];

  constructor(filename: string) {
    this.handle = openSync(filename, 'r');
    if (this.handle < 0) iError(`Couldn't open ${filename}`);
    const header = readHeader(this.handle);
    if (header.identification !== 'IWAD' && header.identification !== 'PWAD')
      iError(`${filename} is not a valid WAD file`);
    this.numLumps = header.numlumps;
    this.infotable = readInfotable(this.handle, header.infotableofs, this.numLumps);
  }

  getLump(name: string): Uint8Array {
    const idx = this.infotable.findIndex(l => l.name === name);
    if (idx < 0) iError(`W_GetNumForName: ${name} not found`);
    return readLump(this.handle, this.infotable[idx]);
  }
}
